class Solution:
    def minimumDeleteSum(self, s1, s2):
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def go(i, j):
            if i == len(s1):
                return sum(ord(c) for c in s2[j:])
            if j == len(s2):
                return sum(ord(c) for c in s1[i:])
            if s1[i] == s2[j]:
                return go(i + 1, j + 1)
            return min(ord(s1[i]) + go(i + 1, j), ord(s2[j]) + go(i, j + 1))
        return go(0, 0)

